// Fn traits require nightly. On stable Rust, use a method or a newtype over Box<dyn Fn>.
// Option 1: provide a call() method
struct Adder(i32);

impl Adder {
    fn call(&self, x: i32) -> i32 { self.0 + x }
}

// Option 2: return a closure
fn make_adder(n: i32) -> impl Fn(i32) -> i32 {
    move |x| x + n
}

// Option 3: newtype over a boxed Fn for dynamic dispatch
struct DynAdder(Box<dyn Fn(i32) -> i32>);

impl DynAdder {
    fn new(n: i32) -> Self { DynAdder(Box::new(move |x| x + n)) }
    fn call(&self, x: i32) -> i32 { (self.0)(x) }
}

fn apply(f: impl Fn(i32) -> i32, x: i32) -> i32 { f(x) }

fn main() {
    let a = Adder(5);
    println!("{}", a.call(10)); // method call

    let add3 = make_adder(3);
    println!("{}", add3(7));    // closure call
    println!("{}", apply(add3, 20));

    let da = DynAdder::new(10);
    println!("{}", da.call(5));
