use std::ops::Add;

#[derive(Debug, Clone)]
struct Poly(Vec<f64>);

fn add_slices(a: &[f64], b: &[f64]) -> Vec<f64> {
    let n = a.len().max(b.len());
    let mut r = vec![0.0; n];
    for (i, &c) in a.iter().enumerate() { r[i] += c; }
    for (i, &c) in b.iter().enumerate() { r[i] += c; }
    r
}

// Owned + Owned
impl Add for Poly {
    type Output = Poly;
    fn add(self, rhs: Poly) -> Poly { Poly(add_slices(&self.0, &rhs.0)) }
}

// &Poly + &Poly — doesn't consume either
impl<'a, 'b> Add<&'b Poly> for &'a Poly {
    type Output = Poly;
    fn add(self, rhs: &'b Poly) -> Poly { Poly(add_slices(&self.0, &rhs.0)) }
}

fn main() {
    let p = Poly(vec![1.0, 2.0]);
