use std::ops::Index;

// Index must return a reference to existing data — not an Option wrapping a value.
// For safe access, provide a get() method instead.
struct SafeVec<T>(Vec<T>);

impl<T> SafeVec<T> {
    fn get(&self, idx: usize) -> Option<&T> {
        self.0.get(idx)
    }

    fn get_or<'a>(&'a self, idx: usize, default: &'a T) -> &'a T {
        self.0.get(idx).unwrap_or(default)
    }
}

// Index for direct access (panics on OOB like Vec does):
impl<T> Index<usize> for SafeVec<T> {
    type Output = T;
    fn index(&self, idx: usize) -> &T {
        &self.0[idx]
    }
}

fn main() {
    let v = SafeVec(vec![10, 20, 30]);
    println!("{:?}", v.get(1));   // Some(20)
    println!("{:?}", v.get(99));  // None
    println!("{}", v[2]);         // 30
